/**
 * Generate investor test data based on pattern
 *
 * @param pattern - The test data pattern to generate
 * @param overrides - Optional field overrides
 * @returns Generated test data
 *
 * @example
 * ```typescript
 * // Generate complete test data
 * const data = generateInvestorTestData('complete');
 *
 * // Generate unique test data with overrides
 * const customData = generateInvestorTestData('unique', {
 *   is_active: false,
 * });
 * ```
 */
export function generateInvestorTestData(
  pattern: TestDataPattern = 'complete',
  overrides: Partial<InvestorCreateRequest> = {}
): InvestorCreateRequest {
  let baseData: InvestorCreateRequest;

  switch (pattern) {
    case 'minimal':
      baseData = { ...minimalInvestorFixture };
      break;

    case 'complete':
      baseData = { ...completeInvestorFixture };
      break;

    case 'invalid':
      // Return invalid data (caller should handle validation failure)
      baseData = { ...invalidInvestorFixture } as InvestorCreateRequest;
      break;

    case 'unique':
      // Generate fresh unique values for each call
      baseData = {
        ...uniqueInvestorFixture,
        name: `Test Investor ${generateUniqueId()}`,
      };
      break;

    default:
      baseData = { ...completeInvestorFixture };
  }

  return { ...baseData, ...overrides };
}

/**
 * Generate multiple investor fixtures
 *
 * @param count - Number of fixtures to generate
 * @param pattern - The test data pattern to use as base
 * @param modifier - Optional function to modify each fixture
 * @returns Array of generated test data
 *
 * @example
 * ```typescript
 * // Generate 5 unique fixtures
 * const fixtures = generateMultipleInvestorFixtures(5, 'unique');
 *
 * // Generate fixtures with sequential numbering
 * const numbered = generateMultipleInvestorFixtures(3, 'complete', (data, index) => ({
 *   ...data,
 *   name: `Investor #${index + 1}`,
 * }));
 * ```
 */
export function generateMultipleInvestorFixtures(
  count: number,
  pattern: TestDataPattern = 'unique',
  modifier?: (data: InvestorCreateRequest, index: number) => InvestorCreateRequest
): InvestorCreateRequest[] {
  const fixtures: InvestorCreateRequest[] = [];

  for (let i = 0; i < count; i++) {
    let fixture = generateInvestorTestData(pattern);

    if (modifier) {
      fixture = modifier(fixture, i);
    } else if (pattern === 'unique') {
      // Add index to ensure uniqueness even with same timestamp
      fixture.name = `Test Investor ${generateUniqueId()}-${i}`;
    }

    fixtures.push(fixture);
  }

  return fixtures;
}

